const input = $input.first().json;
const token = input.formQueryParameters?.token;
const api_key = input['API Key'];

if (!token) {
  return [{ json: { valid: false, error: 'Missing token.' } }];
}
if (!api_key) {
  return [{ json: { valid: false, error: 'Missing API key.' } }];
}

const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const headers = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

const resp = await $helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/credential_tokens?token=eq.' + token + '&select=*',
  headers
});

if (!resp || !Array.isArray(resp) || resp.length === 0) {
  return [{ json: { valid: false, error: 'Invalid or unknown token.' } }];
}

const row = resp[0];

if (row.used) {
  return [{ json: { valid: false, error: 'This link has already been used.' } }];
}

if (row.expires_at && new Date(row.expires_at) < new Date()) {
  return [{ json: { valid: false, error: 'This link has expired.' } }];
}

return [{ json: {
  valid: true,
  error: '',
  token: token,
  template_id: row.template_id,
  cred_key: row.cred_key,
  cred_label: row.cred_label,
  api_key: api_key
} }];

const input = $input.first().json;
const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const headers = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

// Upsert into template_credentials
await $helpers.httpRequest({
  method: 'POST',
  url: baseUrl + '/rest/v1/template_credentials',
  headers: {
    ...headers,
    'Prefer': 'resolution=merge-duplicates,return=minimal'
  },
  body: {
    template_id: input.template_id,
    cred_key: input.cred_key,
    cred_value: input.api_key,
    updated_at: new Date().toISOString()
  }
});

// Mark token as used
await $helpers.httpRequest({
  method: 'PATCH',
  url: baseUrl + '/rest/v1/credential_tokens?token=eq.' + input.token,
  headers: {
    ...headers,
    'Prefer': 'return=minimal'
  },
  body: {
    used: true
  }
});

return [{ json: { success: true } }];
